+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  EmailNotificationAdapter,
+  InMemoryEmailTransport,
+} from '../../src/adapters/email.adapter.js';
+import type {
+  EmailTransport,
+  RenderedEmail,
+} from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+  return {
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    channel: 'email',
+    notificationType: 'order_confirmation',
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    ...overrides,
+  };
+}
+
+describe('EmailNotificationAdapter', () => {
+  let adapter: EmailNotificationAdapter;
+  let transport: InMemoryEmailTransport;
+
+  beforeEach(() => {
+    transport = new InMemoryEmailTransport();
+    adapter = new EmailNotificationAdapter(undefined, transport);
+  });
+
+  // -----------------------------------------------------------------------
+  // Basic send
+  // -----------------------------------------------------------------------
+
+  it('should deliver an email successfully', async () => {
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(true);
+    const sent = adapter.getSentEmails();
+    expect(sent).toHaveLength(1);
+    expect(sent[0]?.to).toBe('alice@example.com');
+    expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
+  });
+
+  it('should set from address from config', async () => {
+    adapter = new EmailNotificationAdapter(
+      { fromAddress: 'orders@taskflowpro.com' },
+      transport,
+    );
+
+    await adapter.send(makePayload());
+
+    const sent = adapter.getSentEmails();
+    expect(sent[0]?.from).toBe('orders@taskflowpro.com');
+  });
+
+  it('should use default from address when none provided', async () => {
+    await adapter.send(makePayload());
+
+    const sent = adapter.getSentEmails();
+    expect(sent[0]?.from).toBe('noreply@taskflowpro.com');
+  });
+
+  // -----------------------------------------------------------------------
+  // Recipient validation
+  // -----------------------------------------------------------------------
+
+  it('should reject empty recipient', async () => {
+    const result = await adapter.send(makePayload({ recipient: '' }));
+
+    expect(result.success).toBe(false);
+    expect(result.error).toContain('Invalid email address');
+    expect(adapter.getSentEmails()).toHaveLength(0);
+  });
+
+  it('should reject recipient without @ sign', async () => {
+    const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));
+
+    expect(result.success).toBe(false);
+    expect(result.error).toContain('Invalid email address');
+  });
+
+  it('should reject recipient without domain', async () => {
+    const result = await adapter.send(makePayload({ recipient: 'user@' }));
+
+    expect(result.success).toBe(false);
+    expect(result.error).toContain('Invalid email address');
+  });
+
+  it('should accept valid email addresses', async () => {
+    const result = await adapter.send(makePayload({ recipient: 'user@domain.co.uk' }));
+    expect(result.success).toBe(true);
+  });
+
+  // -----------------------------------------------------------------------
+  // Template rendering
+  // -----------------------------------------------------------------------
+
+  it('should render order_confirmation template with HTML', () => {
+    const rendered = adapter.renderEmail(makePayload());
+
+    expect(rendered.htmlBody).toContain('<h1>Order Confirmation</h1>');
+    expect(rendered.htmlBody).toContain('Widget x2');
+    expect(rendered.htmlBody).toContain('order-1');
+    expect(rendered.textBody).toContain('Thank you for your order!');
+  });
+
+  it('should render order_status_update template', () => {
+    const rendered = adapter.renderEmail(
+      makePayload({
+        notificationType: 'order_status_update',
+        subject: 'Order Update: order-1',
+        body: 'Your order status has changed from pending to confirmed.',
+      }),
+    );
+
+    expect(rendered.htmlBody).toContain('<h1>Order Status Update</h1>');
+    expect(rendered.textBody).toContain('pending to confirmed');
+  });
+
+  it('should render user_welcome template', () => {
+    const rendered = adapter.renderEmail(
+      makePayload({
+        notificationType: 'user_welcome',
+        subject: 'Welcome!',
+        body: 'Welcome aboard, Alice!',
+        metadata: undefined,
+      }),
+    );
+
+    expect(rendered.htmlBody).toContain('Welcome to TaskFlow Pro!');
+    expect(rendered.textBody).toContain('reply to this email');
+  });
+
+  it('should render user_updated template', () => {
+    const rendered = adapter.renderEmail(
+      makePayload({
+        notificationType: 'user_updated',
+        subject: 'Account Updated',
+        body: 'Your email address has been changed.',
+        metadata: undefined,
+      }),
+    );
+
+    expect(rendered.htmlBody).toContain('Account Updated');
+    expect(rendered.textBody).toContain('contact support immediately');
+  });
+
+  it('should escape HTML in body text', () => {
+    const rendered = adapter.renderEmail(
+      makePayload({
+        body: 'Items: <script>alert("xss")</script>',
+      }),
+    );
+
+    expect(rendered.htmlBody).not.toContain('<script>');
+    expect(rendered.htmlBody).toContain('&lt;script&gt;');
+  });
+
+  it('should include metadata orderId in rendered email', () => {
+    const rendered = adapter.renderEmail(makePayload());
+
+    expect(rendered.htmlBody).toContain('order-1');
+    expect(rendered.textBody).toContain('Order ID: order-1');
+  });
+
+  // -----------------------------------------------------------------------
+  // Retry logic
+  // -----------------------------------------------------------------------
+
+  it('should retry on transport failure', async () => {
+    let attempts = 0;
+    const failingTransport: EmailTransport = {
+      async deliver() {
+        attempts++;
+        if (attempts < 3) {
+          throw new Error('Connection timeout');
+        }
+      },
+    };
+
+    adapter = new EmailNotificationAdapter({ maxRetries: 2 }, failingTransport);
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(true);
+    expect(attempts).toBe(3); // 1 initial + 2 retries
+  });
+
+  it('should return failure after exhausting retries', async () => {
+    const failingTransport: EmailTransport = {
+      async deliver() {
+        throw new Error('Permanent failure');
+      },
+    };
+
+    adapter = new EmailNotificationAdapter({ maxRetries: 1 }, failingTransport);
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(false);
+    expect(result.error).toBe('Permanent failure');
+  });
+
+  it('should succeed on first attempt when no errors', async () => {
+    let attempts = 0;
+    const countingTransport: EmailTransport = {
+      async deliver() {
+        attempts++;
+      },
+    };
+
+    adapter = new EmailNotificationAdapter({ maxRetries: 3 }, countingTransport);
+    await adapter.send(makePayload());
+
+    expect(attempts).toBe(1);
+  });
+
+  // -----------------------------------------------------------------------
+  // Configuration
+  // -----------------------------------------------------------------------
+
+  it('should expose config via getConfig', () => {
+    adapter = new EmailNotificationAdapter({
+      fromAddress: 'custom@example.com',
+      replyTo: 'support@example.com',
+      maxRetries: 5,
+    });
+
+    const config = adapter.getConfig();
+    expect(config.fromAddress).toBe('custom@example.com');
+    expect(config.replyTo).toBe('support@example.com');
+    expect(config.maxRetries).toBe(5);
+  });
+
+  it('should set replyTo to fromAddress when not specified', () => {
+    const rendered = adapter.renderEmail(makePayload());
+    expect(rendered.replyTo).toBe('noreply@taskflowpro.com');
+  });
+
+  it('should use explicit replyTo when set', () => {
+    adapter = new EmailNotificationAdapter(
+      { replyTo: 'support@taskflowpro.com' },
+      transport,
+    );
+
+    const rendered = adapter.renderEmail(makePayload());
+    expect(rendered.replyTo).toBe('support@taskflowpro.com');
+  });
+
+  // -----------------------------------------------------------------------
+  // Clearing
+  // -----------------------------------------------------------------------
+
+  it('should clear sent emails', async () => {
+    await adapter.send(makePayload());
+    expect(adapter.getSentEmails()).toHaveLength(1);
+
+    adapter.clearSentEmails();
+    expect(adapter.getSentEmails()).toHaveLength(0);
+  });
+
+  // -----------------------------------------------------------------------
+  // Channel
+  // -----------------------------------------------------------------------
+
+  it('should report email channel', () => {
+    expect(adapter.channel).toBe('email');
+  });
+});
+
+describe('InMemoryEmailTransport', () => {
+  it('should store and retrieve delivered emails', async () => {
+    const transport = new InMemoryEmailTransport();
+
+    await transport.deliver({
+      to: 'test@example.com',
+      from: 'noreply@taskflowpro.com',
+      replyTo: 'noreply@taskflowpro.com',
+      subject: 'Test',
+      textBody: 'Hello',
+      htmlBody: '<p>Hello</p>',
+    });
+
+    const emails = transport.getDeliveredEmails();
+    expect(emails).toHaveLength(1);
+    expect(emails[0]?.to).toBe('test@example.com');
+  });
+
+  it('should clear delivered emails', async () => {
+    const transport = new InMemoryEmailTransport();
+
+    await transport.deliver({
+      to: 'test@example.com',
+      from: 'noreply@taskflowpro.com',
+      replyTo: 'noreply@taskflowpro.com',
+      subject: 'Test',
+      textBody: 'Hello',
+      htmlBody: '<p>Hello</p>',
+    });
+
+    transport.clear();
+    expect(transport.getDeliveredEmails()).toHaveLength(0);
+  });
+});

