/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel with:
 * - Template rendering per notification type (HTML + plain text)
 * - Recipient email validation
 * - Configurable SMTP settings (from address, reply-to, etc.)
 * - Retry support with configurable max attempts
 *
 * In production the transport would integrate with SMTP / SendGrid / SES.
 * The default transport stores emails in memory for testing.
 */

import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationChannel,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

export interface EmailConfig {
  /** Sender address shown in the "From" header. */
  fromAddress: string;
  /** Optional reply-to address. Defaults to fromAddress. */
  replyTo?: string;
  /** Maximum delivery attempts before giving up. */
  maxRetries: number;
}

const DEFAULT_EMAIL_CONFIG: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  maxRetries: 2,
};

// ---------------------------------------------------------------------------
// Email template types
// ---------------------------------------------------------------------------

export interface RenderedEmail {
  to: string;
  from: string;
  replyTo: string;
  subject: string;
  textBody: string;
  htmlBody: string;
}

/**
 * Record of a successfully sent email — includes rendered content.
 */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  textBody: string;
  htmlBody: string;
  sentAt: Date;
}

// ---------------------------------------------------------------------------
// Transport abstraction
// ---------------------------------------------------------------------------

/**
 * Pluggable transport that actually delivers the email.
 * The default implementation stores emails in memory (for testing).
 * In production, swap this for an SMTP or API-backed transport.
 */
export interface EmailTransport {
  deliver(email: RenderedEmail): Promise<void>;
}

/**
 * In-memory transport — stores delivered emails for inspection in tests.
 */
export class InMemoryEmailTransport implements EmailTransport {
  private deliveredEmails: SentEmail[] = [];

  async deliver(email: RenderedEmail): Promise<void> {
    this.deliveredEmails.push({
      to: email.to,
      from: email.from,
      subject: email.subject,
      textBody: email.textBody,
      htmlBody: email.htmlBody,
      sentAt: new Date(),
    });
  }

  getDeliveredEmails(): SentEmail[] {
    return [...this.deliveredEmails];
  }

  clear(): void {
    this.deliveredEmails = [];
  }
}

// ---------------------------------------------------------------------------
// Template rendering
// ---------------------------------------------------------------------------

type TemplateRenderer = (payload: NotificationPayload) => { text: string; html: string };

const EMAIL_TEMPLATES: Record<NotificationType, TemplateRenderer> = {
  order_confirmation(payload) {
    const text = [
      `Hi,`,
      ``,
      `${payload.body}`,
      ``,
      payload.metadata?.orderId ? `Order ID: ${payload.metadata.orderId}` : '',
      ``,
      `Thank you for your order!`,
      `— The TaskFlow Pro Team`,
    ]
      .filter(Boolean)
      .join('\n');

    const html = [
