// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function validateRecipient(recipient: string): string | null {
  if (!recipient || !EMAIL_REGEX.test(recipient)) {
    return `Invalid email address: ${recipient}`;
  }
  return null;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ---------------------------------------------------------------------------
// Adapter
// ---------------------------------------------------------------------------

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';

  private logger = new Logger('EmailAdapter');
  private config: EmailConfig;
  private transport: EmailTransport;

  constructor(config?: Partial<EmailConfig>, transport?: EmailTransport) {
    this.config = { ...DEFAULT_EMAIL_CONFIG, ...config };
    this.transport = transport ?? new InMemoryEmailTransport();
  }

  /**
   * Render a notification payload into a full email and deliver it.
   * Validates the recipient, renders templates, and retries on failure.
   *
   * Per the NotificationAdapter contract this method never throws.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      // 1. Validate recipient
      const validationError = validateRecipient(payload.recipient);
      if (validationError) {
        this.logger.error(validationError);
        return { success: false, error: validationError };
      }

      // 2. Render template
      const rendered = this.renderEmail(payload);

      // 3. Attempt delivery with retries
      let lastError: string | undefined;
      for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
        try {
          await this.transport.deliver(rendered);
          this.logger.info(
            `Email delivered to ${payload.recipient}: ${payload.subject}`,
          );
          return { success: true };
        } catch (err: unknown) {
          lastError = err instanceof Error ? err.message : 'Transport error';
          this.logger.warn(
            `Delivery attempt ${attempt + 1} failed for ${payload.recipient}: ${lastError}`,
          );
        }
      }

      this.logger.error(
        `All delivery attempts exhausted for ${payload.recipient}: ${lastError}`,
      );
      return { success: false, error: lastError };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Unexpected error sending to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Render a NotificationPayload into a fully formed email using the
   * template for the payload's notificationType.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const template = EMAIL_TEMPLATES[payload.notificationType];
    const { text, html } = template(payload);

    return {
      to: payload.recipient,
      from: this.config.fromAddress,
      replyTo: this.config.replyTo ?? this.config.fromAddress,
      subject: payload.subject,
      textBody: text,
      htmlBody: html,
    };
  }

  // -----------------------------------------------------------------------
  // Convenience accessors (primarily for testing)
  // -----------------------------------------------------------------------

  /**
   * Get all emails sent through this adapter.
   * Only works when using InMemoryEmailTransport.
   */
  getSentEmails(): SentEmail[] {
    if (this.transport instanceof InMemoryEmailTransport) {
      return this.transport.getDeliveredEmails();
    }
    return [];
  }

  /**
   * Clear sent email history.
   * Only works when using InMemoryEmailTransport.
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryEmailTransport) {
      this.transport.clear();
    }
  }

  /**
   * Get the current configuration (useful for testing).
   */
  getConfig(): Readonly<EmailConfig> {
    return { ...this.config };
  }
}

